// 1. Sadə Şərti Tip
type IsString<T> = T extends string ? "yes" : "no";
type Test1 = IsString<string>; // "yes"
type Test2 = IsString<number>; // "no"
console.log("Test1 is: " + ("yes" as Test1)); // Çıxış: Test1 is: yes
console.log("Test2 is: " + ("no" as Test2)); // Çıxış: Test2 is: no

// 2. Şərti Tip ilə Funksiya
function getValue<T>(value: T): T extends string ? string : number {
  return (typeof value === "string" ? value.toUpperCase() : 0) as any;
}
console.log(getValue("hello")); // Çıxış: HELLO
console.log(getValue(42)); // Çıxış: 0

// 3. Şərti Tip ilə Union Tipləri
type AllowedType = string | number;
type Restrict<T> = T extends AllowedType ? T : never;
type StringOrNumber = Restrict<string | number | boolean>;
const valid: StringOrNumber = "Test"; // İşləyir
const valid2: StringOrNumber = 123; // İşləyir
// const invalid: StringOrNumber = true; // Səhv: boolean never tipinə uyğun deyil
console.log(valid); // Çıxış: Test
console.log(valid2); // Çıxış: 123

// 4. Infer ilə Şərti Tip
type ReturnType<T> = T extends (...args: any[]) => infer R ? R : never;
type Func = () => string;
type FuncReturn = ReturnType<Func>; // string
const funcReturn: FuncReturn = "Hello";
console.log(funcReturn); // Çıxış: Hello

// 5. Şərti Tip ilə Interfeys
interface Item<T> {
  data: T extends string ? string : number;
}
const stringItem: Item<string> = { data: "Hello" };
const numberItem: Item<number> = { data: 123 };
console.log(stringItem); // Çıxış: { data: "Hello" }
console.log(numberItem); // Çıxış: { data: 123 }

// 6. Şərti Tip ilə Sinif
class Processor<T> {
  process(value: T): T extends string ? string : number {
    return (typeof value === "string" ? value.toUpperCase() : 0) as any;
  }
}
const stringProcessor = new Processor<string>();
const numberProcessor = new Processor<number>();
console.log(stringProcessor.process("test")); // Çıxış: TEST
console.log(numberProcessor.process(42)); // Çıxış: 0

// 7. Şərti Tip ilə Mapped Types
type NonNullable<T> = T extends null | undefined ? never : T;
type SafeString = NonNullable<string | null>;
const safe: SafeString = "Hello"; // İşləyir
// const unsafe: SafeString = null; // Səhv: null never tipinə uyğun deyil
console.log(safe); // Çıxış: Hello

// Sadə mağaza sistemi
type ProductData<T> = T extends string ? { id: string; name: T } : { id: string; price: T };
class ProductStore<T> {
  products: ProductData<T>[] = [];
  add(id: string, data: T): void {
    const product: ProductData<T> = (typeof data === "string" ? { id, name: data } : { id, price: data }) as any;
    this.products.push(product);
  }
  getById(id: string): ProductData<T> | undefined {
    return this.products.find(p => p.id === id);
  }
}
const stringStore = new ProductStore<string>();
stringStore.add("P001", "Laptop");
console.log(stringStore.getById("P001")); // Çıxış: { id: "P001", name: "Laptop" }

const numberStore = new ProductStore<number>();
numberStore.add("P002", 999);
console.log(numberStore.getById("P002")); // Çıxış: { id: "P002", price: 999 }

// Şərti tip ilə funksiya
type ProcessResult<T> = T extends string ? string : number;
function processProduct<T>(data: T): ProcessResult<T> {
  return (typeof data === "string" ? data.toUpperCase() : 0) as any;
}
console.log(processProduct("Laptop")); // Çıxış: LAPTOP
console.log(processProduct(999)); // Çıxış: 0

